function nextHighTide(tides, after) {
  const next = tides.find((t) => new Date(t.time) > new Date(after) && t.type === "high");
  if (!next) throw new Error("no upcoming high tide in data");
  return next;
}

module.exports = { nextHighTide };

#!/usr/bin/env bash
# Run ONE isolated pi eval leg and capture its raw evidence.
#
# The atom the eval rig composes: a probe is one leg, a pilot is many legs
# sequenced (see eval-pilot.sh). A baseline `pi` agent, on a chosen model, reads
# the real installed Shipshape role skill(s) and acts over a scaffolded sim; we
# capture everything raw (session JSONL, stdout/stderr, tree diff, git log) so
# the deterministic fold (eval-map.py) never needs to re-spend a model call.
#
# Isolation is total: a throwaway $HOME/XDG per leg (pi's own config/creds stay
# out of the real home), the sim workspace as cwd, --approve so non-interactive
# -p mode never derails into the confirm/ask loop (proven flake, 2026-07-23).
#
# Usage:
#   eval-leg.sh --model <id> --workspace <dir> --out <dir> \
#     --skill <path> [--skill <path>...] (--task <str> | --task-file <path>) \
#     [--provider openrouter] [--name <leg>] [--timeout-s 900]
#
# The OpenRouter key is read from $OPENROUTER_API_KEY, else mapped from
# ~/yoink/.env's HARNESS_OPENROUTER_API_KEY. Never printed.
set -euo pipefail

PI="${PI_BIN:-$HOME/jolly/node_modules/.bin/pi}"
PROVIDER="openrouter"
MODEL=""; WORKSPACE=""; OUT=""; TASK=""; TASKFILE=""; NAME=""; TIMEOUT_S=900
SKILLS=()

while [ $# -gt 0 ]; do
  case "$1" in
    --model)      MODEL="$2"; shift 2;;
    --provider)   PROVIDER="$2"; shift 2;;
    --workspace)  WORKSPACE="$2"; shift 2;;
    --out)        OUT="$2"; shift 2;;
    --skill)      SKILLS+=("$2"); shift 2;;
    --task)       TASK="$2"; shift 2;;
    --task-file)  TASKFILE="$2"; shift 2;;
    --name)       NAME="$2"; shift 2;;
    --timeout-s)  TIMEOUT_S="$2"; shift 2;;
    *) echo "eval-leg.sh: unknown arg '$1'" >&2; exit 2;;
  esac
done

[ -n "$MODEL" ]     || { echo "eval-leg.sh: --model required" >&2; exit 2; }
[ -n "$WORKSPACE" ] || { echo "eval-leg.sh: --workspace required" >&2; exit 2; }
[ -n "$OUT" ]       || { echo "eval-leg.sh: --out required" >&2; exit 2; }
[ -d "$WORKSPACE" ] || { echo "eval-leg.sh: workspace '$WORKSPACE' not a dir" >&2; exit 2; }
[ "${#SKILLS[@]}" -gt 0 ] || { echo "eval-leg.sh: at least one --skill required" >&2; exit 2; }
[ -x "$PI" ] || { echo "eval-leg.sh: pi not found/executable at $PI (set PI_BIN)" >&2; exit 2; }
if [ -n "$TASKFILE" ]; then
  [ -f "$TASKFILE" ] || { echo "eval-leg.sh: --task-file '$TASKFILE' missing" >&2; exit 2; }

{
  "name": "tidewatch5",
  "version": "0.1.0",
  "private": true,
  "scripts": {
    "test": "cucumber-js"
  },
  "devDependencies": {
    "@cucumber/cucumber": "^13.0.0"
  }
}

const { Given, When, Then } = require("@cucumber/cucumber");
const assert = require("assert");
const fs = require("fs");
const path = require("path");
const { nextHighTide } = require("../../src/tide");

Given("the tide table for Fundy Cove", function () {
  this.tides = JSON.parse(fs.readFileSync(path.join(__dirname, "..", "..", "data", "tides.json"), "utf8"));
});

When("I ask for the next high tide after {string}", function (after) {
  try {
    this.result = nextHighTide(this.tides, after);
  } catch (e) {
    this.error = e;
  }
});

Then("the predicted high tide is at {string} with height {float}", function (time, height) {
  assert.equal(this.result.time, time);
  assert.equal(this.result.height, height);
});

Then("the prediction fails with {string}", function (msg) {
  assert.equal(this.error.message, msg);
});

#!/usr/bin/env python3
"""Fold a pi eval leg's session JSONL into a role-phased affordance map.

PURE over captured files — no model calls, no network — so it is re-runnable
against banked raw and testable on a committed fixture (data/eval-fixture/).
This is the live sibling of doctrine-sections.py: where that prices doctrine
statically, this reports where a baseline agent actually spent its budget and
which role skill it was following when it did.

Usage:
  eval-map.py <leg-dir-or-session.jsonl> [more...]   # per-leg map + roll-up
  eval-map.py --json <...>                            # machine-readable

Session schema (pi 0.81, --mode json session file), locked 2026-07-23:
  line {"type":"message","message":{role, content:[part...], usage?}}
  role in {user, assistant, toolResult}
  assistant.usage = {input,output,cacheRead,cacheWrite,reasoning,totalTokens,cost:{total,...}}
  content part types: thinking | toolCall{name,arguments} | text
  a role-skill load shows as a `read` toolCall whose path ends in SKILL.md.
"""
import json
import os
import re
import sys

# Role skills a Shipshape agent may read-and-follow. Order is only for display.
ROLES = ["shipshape", "captain", "qm", "crew", "boatswain", "shipwright"]


def role_of_path(path):
    """The Shipshape role a read SKILL.md path names, or None."""
    if not path or "SKILL.md" not in path:
        return None
    # .../skills/<role>/SKILL.md  — take the dir holding SKILL.md.
    parts = re.split(r"[/\\]", path)
    try:
        i = parts.index("SKILL.md")
    except ValueError:
        return None
    parent = parts[i - 1] if i > 0 else ""
    parent = parent.lower()
    return parent if parent in ROLES else None


def session_path(target):
    """Resolve a leg dir or a jsonl path to the session file."""
    if os.path.isdir(target):
        # Prefer a captured session.jsonl; else the newest *.jsonl under it.
        direct = os.path.join(target, "session.jsonl")
        if os.path.isfile(direct):
            return direct
        found = []
        for root, _dirs, files in os.walk(target):
            for f in files:
                if f.endswith(".jsonl"):
                    found.append(os.path.join(root, f))
        return sorted(found)[-1] if found else None
    return target if os.path.isfile(target) else None


def read_turns(session_file):
    """Every assistant model invocation, in order, as the agent recorded it.

    An assistant message with no usage is not an accounted invocation and is
    skipped — a leg whose agent recorded no usage yields an empty list, which
    the caller reddens rather than reporting a cost of zero.
    """
    turns = []
    with open(session_file, encoding="utf-8") as fh:
        for line in fh:
            line = line.strip()
            if not line:
                continue
            try:
                ev = json.loads(line)
            except json.JSONDecodeError:
                continue
            if ev.get("type") != "message":
                continue
            msg = ev.get("message") or {}
